"use client";

import { useState, useEffect, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Search, Menu, X, Zap } from "lucide-react";
import { cn } from "@/lib/utils";
import SearchCommandPalette from "./SearchCommandPalette";

const NAV_LINKS = [
  { label: "Explore Startups", href: "#startups" },
  { label: "Investors", href: "#investors" },
  { label: "How it Works", href: "#how-it-works" },
  { label: "Startup Stories", href: "#stories" },
  { label: "About", href: "#about" },
];

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);
  const [paletteOpen, setPaletteOpen] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const openPalette = useCallback(() => setPaletteOpen(true), []);

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === "k") {
        e.preventDefault();
        openPalette();
      }
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [openPalette]);

  return (
    <>
      <motion.header
        initial={{ y: -80, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        transition={{ duration: 0.6, ease: "easeOut" }}
        className={cn(
          "fixed top-0 left-0 right-0 z-50 transition-all duration-300",
          scrolled
            ? "glass-strong border-b border-white/8 py-3"
            : "bg-transparent py-5"
        )}
      >
        <div className="max-w-7xl mx-auto px-4 sm:px-6 flex items-center gap-4">
          {/* Logo */}
          <a href="#" className="flex items-center gap-2.5 mr-2 flex-shrink-0">
            <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-violet-500 to-indigo-600 flex items-center justify-center shadow-lg shadow-violet-500/30">
              <Zap className="w-4.5 h-4.5 text-white fill-white" size={18} />
            </div>
            <span className="font-bold text-white text-lg tracking-tight">
              Karo<span className="text-violet-400">Pitch</span>
            </span>
          </a>

          {/* Center Search Bar */}
          <div className="flex-1 max-w-sm mx-auto hidden md:block">
            <button
              onClick={openPalette}
              className="w-full flex items-center gap-2 px-3 py-2 rounded-lg bg-white/5 border border-white/8 hover:border-violet-500/30 hover:bg-white/8 transition-all text-left group"
            >
              <Search className="w-3.5 h-3.5 text-slate-500 group-hover:text-violet-400 transition-colors flex-shrink-0" />
              <span className="text-sm text-slate-500 flex-1">
                Search startups, investors...
              </span>
              <kbd className="text-xs text-slate-600 bg-white/5 px-1.5 py-0.5 rounded hidden lg:inline">
                ⌘K
              </kbd>
            </button>
          </div>

          {/* Nav Links */}
          <nav className="hidden lg:flex items-center gap-1">
            {NAV_LINKS.map((link) => (
              <a
                key={link.label}
                href={link.href}
                className="text-sm text-slate-400 hover:text-slate-100 px-3 py-1.5 rounded-lg hover:bg-white/5 transition-all duration-200 whitespace-nowrap"
              >
                {link.label}
              </a>
            ))}
          </nav>

          {/* Right buttons */}
          <div className="flex items-center gap-2 ml-auto lg:ml-0 flex-shrink-0">
            <button className="hidden sm:inline-flex text-sm text-slate-400 hover:text-white px-3 py-1.5 rounded-lg hover:bg-white/5 transition-all">
              Login
            </button>
            <button className="btn-primary text-white text-sm relative z-10 inline-flex items-center gap-1.5 whitespace-nowrap">
              <Zap className="w-3.5 h-3.5" />
              Apply to Pitch
            </button>

            {/* Mobile menu toggle */}
            <button
              onClick={() => setMobileOpen(!mobileOpen)}
              className="lg:hidden w-9 h-9 flex items-center justify-center rounded-lg hover:bg-white/5 transition-colors"
            >
              {mobileOpen ? (
                <X className="w-5 h-5 text-slate-300" />
              ) : (
                <Menu className="w-5 h-5 text-slate-300" />
              )}
            </button>
          </div>
        </div>

        {/* Mobile menu */}
        <AnimatePresence>
          {mobileOpen && (
            <motion.div
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: "auto" }}
              exit={{ opacity: 0, height: 0 }}
              transition={{ duration: 0.25 }}
              className="lg:hidden border-t border-white/8 glass-strong"
            >
              <div className="max-w-7xl mx-auto px-4 py-4 flex flex-col gap-1">
                <button
                  onClick={openPalette}
                  className="flex items-center gap-2 px-3 py-2 rounded-lg bg-white/5 border border-white/8 mb-2"
                >
                  <Search className="w-4 h-4 text-slate-500" />
                  <span className="text-sm text-slate-500">
                    Search startups, investors...
                  </span>
                </button>
                {NAV_LINKS.map((link) => (
                  <a
                    key={link.label}
                    href={link.href}
                    onClick={() => setMobileOpen(false)}
                    className="text-sm text-slate-400 hover:text-slate-100 px-3 py-2.5 rounded-lg hover:bg-white/5 transition-all"
                  >
                    {link.label}
                  </a>
                ))}
                <div className="flex gap-2 mt-2 pt-2 border-t border-white/5">
                  <button className="flex-1 text-sm text-slate-300 py-2 rounded-lg bg-white/5 hover:bg-white/8 transition-all">
                    Login
                  </button>
                  <button className="flex-1 btn-primary text-white text-sm relative z-10">
                    Apply to Pitch
                  </button>
                </div>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </motion.header>

      {/* Command Palette */}
      <AnimatePresence>
        {paletteOpen && (
          <SearchCommandPalette
            isOpen={paletteOpen}
            onClose={() => setPaletteOpen(false)}
          />
        )}
      </AnimatePresence>
    </>
  );
}
