"use client";

import Tilt from "react-parallax-tilt";
import { MapPin, TrendingUp, ArrowUpRight } from "lucide-react";
import { motion } from "framer-motion";

export interface Startup {
  id: string;
  name: string;
  tagline: string;
  category: string;
  location: string;
  stage: string;
  fundingTarget: string;
  raised: number; // percentage
  founderName: string;
  founderInitials: string;
  avatarColor: string;
  categoryColor: string;
  logo: string;
}

const categoryColors: Record<string, string> = {
  AgriTech: "bg-emerald-500/15 text-emerald-400 border-emerald-500/20",
  EdTech: "bg-blue-500/15 text-blue-400 border-blue-500/20",
  FinTech: "bg-violet-500/15 text-violet-400 border-violet-500/20",
  HealthTech: "bg-rose-500/15 text-rose-400 border-rose-500/20",
  CleanTech: "bg-teal-500/15 text-teal-400 border-teal-500/20",
  LogiTech: "bg-amber-500/15 text-amber-400 border-amber-500/20",
  SaaS: "bg-indigo-500/15 text-indigo-400 border-indigo-500/20",
  RetailTech: "bg-pink-500/15 text-pink-400 border-pink-500/20",
};

export default function StartupCard({ startup }: { startup: Startup }) {
  const colorClass =
    categoryColors[startup.category] ||
    "bg-slate-500/15 text-slate-400 border-slate-500/20";

  return (
    <Tilt
      tiltMaxAngleX={8}
      tiltMaxAngleY={8}
      glareEnable={true}
      glareMaxOpacity={0.08}
      glareColor="#8b5cf6"
      glarePosition="all"
      glareBorderRadius="16px"
      transitionSpeed={400}
      className="rounded-2xl"
    >
      <motion.div
        className="glass rounded-2xl p-5 h-full flex flex-col gap-4 cursor-pointer group relative overflow-hidden"
        whileHover={{ borderColor: "rgba(139,92,246,0.3)" }}
        style={{ border: "1px solid rgba(255,255,255,0.08)" }}
      >
        {/* Gradient overlay on hover */}
        <div className="absolute inset-0 bg-gradient-to-br from-violet-600/5 to-blue-600/3 opacity-0 group-hover:opacity-100 transition-opacity duration-300 pointer-events-none rounded-2xl" />

        {/* Header */}
        <div className="flex items-start justify-between relative z-10">
          <div className="flex items-center gap-3">
            <div
              className="w-11 h-11 rounded-xl flex items-center justify-center text-lg font-bold"
              style={{ background: startup.avatarColor }}
            >
              {startup.logo}
            </div>
            <div>
              <h3 className="font-semibold text-slate-100 text-sm leading-tight">
                {startup.name}
              </h3>
              <p className="text-xs text-slate-500 mt-0.5 flex items-center gap-1">
                <MapPin className="w-3 h-3" />
                {startup.location}
              </p>
            </div>
          </div>
          <div
            className={`text-xs font-medium px-2.5 py-1 rounded-full border ${colorClass}`}
          >
            {startup.category}
          </div>
        </div>

        {/* Tagline */}
        <p className="text-sm text-slate-400 leading-relaxed relative z-10">
          {startup.tagline}
        </p>

        {/* Funding bar */}
        <div className="relative z-10">
          <div className="flex justify-between text-xs text-slate-500 mb-1.5">
            <span className="flex items-center gap-1">
              <TrendingUp className="w-3 h-3 text-violet-400" />
              Seeking {startup.fundingTarget}
            </span>
            <span className="text-violet-400 font-medium">
              {startup.raised}% raised
            </span>
          </div>
          <div className="h-1.5 bg-white/5 rounded-full overflow-hidden">
            <motion.div
              className="h-full rounded-full bg-gradient-to-r from-violet-500 to-blue-500"
              initial={{ width: 0 }}
              whileInView={{ width: `${startup.raised}%` }}
              transition={{ duration: 1, delay: 0.3 }}
              viewport={{ once: true }}
            />
          </div>
        </div>

        {/* Footer */}
        <div className="flex items-center justify-between pt-1 border-t border-white/5 relative z-10">
          <div className="flex items-center gap-2">
            <div
              className="w-7 h-7 rounded-full flex items-center justify-center text-xs font-bold text-white"
              style={{ background: startup.avatarColor }}
            >
              {startup.founderInitials}
            </div>
            <span className="text-xs text-slate-500">{startup.founderName}</span>
          </div>
          <div className="flex items-center gap-2">
            <span className="text-xs text-slate-600 bg-white/5 px-2 py-0.5 rounded-md">
              {startup.stage}
            </span>
            <ArrowUpRight className="w-4 h-4 text-slate-600 group-hover:text-violet-400 transition-colors" />
          </div>
        </div>
      </motion.div>
    </Tilt>
  );
}
